use std::collections::HashSet;

struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent: Vec<usize> = (0..n).collect();
        let rank: Vec<usize> = vec![1; n];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            self.rank[x_root] += self.rank[y_root];
        }
    }

    fn count(&mut self) -> usize {
        let mut roots = HashSet::new();
        for i in 0..self.parent.len() {
            roots.insert(self.find(i));
        }
        roots.len()
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let mut edges = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));
    let mut max_w = 0;
    if !edges.is_empty() {
        max_w = edges.last().unwrap()[2] as i64;
    }
    let mut low = 0;
    let mut high = max_w;
    let mut answer = high;
    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n);
        for edge in &edges {
            let u = edge[0] as usize;
            let v = edge[1] as usize;
            let w = edge[2];
            if w <= mid {
                dsu.union(u, v);
            }
        }
        let count = dsu.count();
        if count <= k as usize {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    answer
}
